CREATE OR REPLACE VIEW vr_resign_coll (membership_no, loan_contract_no, begining_of_contract, loan_approve_amount, ref_own_no, resign_cause_name, approve_date) AS SELECT sc_lon_m_loan_card.membership_no  /*ผู้กู้*/
, sc_lon_m_contract.loan_contract_no
, sc_lon_m_contract.begining_of_contract 
, sc_lon_m_contract.loan_approve_amount   
, sc_lon_m_contract_coll.ref_own_no   /*ผู้ค้ำ*/
, sc_mem_m_ucf_resign_cause.resign_cause_name  /*เหตุผลการลาออก*/
, sc_mem_m_resign_requestment.approve_date
FROM sc_mem_m_resign_requestment
, sc_lon_m_contract_coll
, sc_lon_m_loan_card
, sc_lon_m_contract  
, sc_mem_m_ucf_resign_cause  
WHERE sc_mem_m_resign_requestment.membership_no = sc_lon_m_contract_coll.ref_own_no 
and sc_lon_m_contract_coll.loan_contract_no = sc_lon_m_loan_card.loan_contract_no 
and sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no   
and sc_mem_m_resign_requestment.resign_code = sc_mem_m_ucf_resign_cause.resign_cause_code  
and sc_mem_m_resign_requestment.approve_result = '1'           
and sc_lon_m_contract_coll.status = '0' 
and sc_lon_m_contract_coll.collateral_type_code = '01' 
and sc_lon_m_loan_card.principal_balance > 0   
/*WHERE*/

--and sc_mem_m_resign_requestment.approve_date between '1/6/2024' and '30/6/2024' ) AND  
ORDER BY sc_lon_m_contract_coll.ref_own_no ASC
, sc_lon_m_loan_card.membership_no ASC;

